// Script: generar_28_ayuda_visible_prevencion.js
// Que hace: corrige el enfoque de la ayuda contextual segun feedback --
// en vez de un icono escondido que hay que descubrir y tocar, ahora cada
// pestana de Prevencion muestra DIRECTAMENTE una tarjetita con el
// mensaje de Chiqui apenas la abres, justo arriba del contenido (arriba
// del grafico de peso, arriba de la lista de vacunas, etc.), sin
// necesitar ningun click adicional.
//
// Se quito el icono de interrogacion del header y el componente
// AyudaChiqui ya no se usa en esta pantalla.
//
// Como correrlo: node generar_28_ayuda_visible_prevencion.js
// Confirma "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
